platform_name = #{platformName}, platform_code = #{platformCode}, platform_logo_url = #{platformLogoUrl}, platform_login_url = #{platformLoginUrl}, platform_home_url = #{platformHomeUrl}, token_domain = #{tokenDomain}, token_key = #{tokenKey}, token_storage_type = #{tokenStorageType}, is_active = #{isActive}, sort_order = #{sortOrder},
