select yy_platform.p_id, yy_platform.platform_name, yy_platform.platform_code, yy_platform.platform_logo_url, yy_platform.platform_login_url, yy_platform.platform_home_url,
       yy_platform.token_domain, up.token as token, yy_platform.token_key, yy_platform.token_storage_type, yy_platform.is_active, yy_platform.sort_order, yy_platform.create_time, yy_platform.update_time
from yy_platform
left join yy_user_platform up on yy_platform.p_id = up.platform_id

     and up.user_id = #{userId}
